public class SimpleMethod {
  public static void printGreeting() {
    System.out.println("Salam, Dünya!");
  }
  public static void main(String[] args) {
    printGreeting();
  }
}
// Çıxış: Salam, Dünya!

public class ParameterizedMethod {
  public static void printSum(int number1, int number2) {
    int sum = number1 + number2;
    System.out.println("Cəm: " + sum);
  }
  public static void main(String[] args) {
    printSum(5, 3);
  }
}
// Çıxış: Cəm: 8

public class ReturnMethod {
  public static int calculateSquare(int number) {
    return number * number;
  }
  public static void main(String[] args) {
    int result = calculateSquare(4);
    System.out.println("Kvadrat: " + result);
  }
}
// Çıxış: Kvadrat: 16

public class MethodOverloading {
  public static void printNumber(int number) {
    System.out.println("Tam ədəd: " + number);
  }
  public static void printNumber(double number) {
    System.out.println("Kəsr ədəd: " + number);
  }
  public static void main(String[] args) {
    printNumber(10);
    printNumber(3.14);
  }
}
// Çıxış:
// Tam ədəd: 10
// Kəsr ədəd: 3.14

public class RecursiveMethod {
  public static int calculateFactorial(int n) {
    if (n <= 1) {
      return 1;
    }
    return n * calculateFactorial(n - 1);
  }
  public static void main(String[] args) {
    int result = calculateFactorial(5);
    System.out.println("5-in faktorialı: " + result);
  }
}
// Çıxış: 5-in faktorialı: 120

public class DiscountCalculator {
  public static double applyDiscount(double price, double discountRate) {
    return price * (1 - discountRate);
  }
  public static void main(String[] args) {
    double originalPrice = 100.0;
    double discount = 0.2; // 20% endirim
    double finalPrice = applyDiscount(originalPrice, discount);
    System.out.println("Son qiymət: " + finalPrice);
  }
}
// Çıxış: Son qiymət: 80.0

